#include <Wire.h>
#include <Adafruit_BMP280.h>
Adafruit_BMP280 bmp;
void setup() {
  Serial.begin(9600);
  if (!bmp.begin(0x76)) {
    Serial.println("BMP280 not found!");
    while (1);
  }
}
void loop() {
  float temp = bmp.readTemperature();
  float pres = bmp.readPressure() / 100.0F; // hPa
  float alt  = bmp.readAltitude(1013.25);    // Sea level hPa
  Serial.print("Temp: "); Serial.print(temp); Serial.print(" C  ");
  Serial.print("Pressure: "); Serial.print(pres); Serial.print(" hPa  ");
  Serial.print("Altitude: "); Serial.print(alt); Serial.println(" m");
  delay(2000);
}
